const PORT = 3000; // 你想要监听的端口
const IP = '166.6.66.6'; // 你想要服务器监听的特定IP

// 创建一个服务器实例
const server = http.createServer((req, res) => {
    // 你的请求处理逻辑
});

// 用指定的IP和端口启动服务器
server.listen(PORT, IP, () => {
    console.log(`服务器正在监听地址 http://${IP}:${PORT}`);
});
```

